public interface Prototype {
    Prototype deepClone();
}

public class ShapeRegistry {
    private static final Map<String, Prototype> registry = new HashMap<>();

    static {
        registry.put("circle",    new Circle(0, 0, 1));
        registry.put("rectangle", new Rectangle(0, 0, 1, 1));
    }

    public static Prototype get(String type) {
        Prototype proto = registry.get(type);
        if (proto == null) throw new IllegalArgumentException("Unknown: " + type);
        return proto.deepClone(); // always a deep copy
    }

    public static void register(String type, Prototype proto) {
        registry.put(type, proto);
    }
}

