}

// Target interface expected by client
public interface JsonParser {
    String parse(String input);
}

// Object Adapter (preferred) — uses composition
public class XmlToJsonAdapter implements JsonParser {
    private final XmlParser adaptee;
    public XmlToJsonAdapter(XmlParser adaptee) { this.adaptee = adaptee; }

    @Override
    public String parse(String json) {
        String xml = convertJsonToXml(json);   // translate
        return adaptee.parseXml(xml);           // delegate
    }

    private String convertJsonToXml(String json) {
        return "<root>" + json + "</root>";
    }
}

