public interface LegacyQueue {
    void enqueue(Object item);
    Object dequeue();
}

public interface ModernQueue {
    void offer(Object item);
    Object poll();
}

public class TwoWayQueueAdapter implements LegacyQueue, ModernQueue {
    private final Deque<Object> storage = new ArrayDeque<>();

    // LegacyQueue
    public void enqueue(Object item) { storage.addLast(item); }
    public Object dequeue()          { return storage.pollFirst(); }

    // ModernQueue
    public void offer(Object item)   { storage.addLast(item); }
    public Object poll()             { return storage.pollFirst(); }
}

// Can be cast to either interface depending on consumer
TwoWayQueueAdapter adapter = new TwoWayQueueAdapter();
LegacyQueue lq = adapter;
ModernQueue mq = adapter;
lq.enqueue("hello");
System.out.println(mq.poll()); // hello

public interface TextProcessor {
    String process(String text);
}

public class PlainTextProcessor implements TextProcessor {
    public String process(String text) { return text; }
}

public abstract class TextDecorator implements TextProcessor {
    protected final TextProcessor wrapped;
    public TextDecorator(TextProcessor t) { this.wrapped = t; }
}

public class UpperCaseDecorator extends TextDecorator {
    public UpperCaseDecorator(TextProcessor t) { super(t); }
    public String process(String text) { return wrapped.process(text).toUpperCase(); }
}

public class TrimDecorator extends TextDecorator {
    public TrimDecorator(TextProcessor t) { super(t); }
    public String process(String text) { return wrapped.process(text).trim(); }
}

// Compose at runtime
TextProcessor tp = new UpperCaseDecorator(
                       new TrimDecorator(
                           new PlainTextProcessor()));
System.out.println(tp.process("  hello world  ")); // "HELLO WORLD"

// Problem with inheritance: N sources x M features = N*M classes
class BufferedFileInputStream    extends FileInputStream { ... }
class GzippedFileInputStream     extends FileInputStream { ... }
class BufferedGzippedFileInputStream extends GzippedFileInputStream { ... }
// 3 sources x 3 features needs 9 subclasses

// Decorator: compose freely, zero class explosion
InputStream in = new BufferedInputStream(
    new GZIPInputStream(
        new FileInputStream("data.gz")
    )
);
// Any combination without new subclasses

// Reading a gzipped, buffered file and parsing as DataInputStream
try (DataInputStream dis = new DataInputStream(
        new BufferedInputStream(
            new GZIPInputStream(
                new FileInputStream("records.dat.gz"))))) {

    while (dis.available() > 0) {
        int id     = dis.readInt();
        String name = dis.readUTF();
        System.out.println(id + ": " + name);
    }
}
// Each wrapper adds one behavior:
// FileInputStream   -> reads raw bytes from file
// GZIPInputStream   -> decompresses on the fly
// BufferedInputStream -> buffers to reduce system calls
// DataInputStream   -> interprets bytes as typed primitives

