class VideoDecoder  { byte[] decode(String f) { return new byte[0]; } }
class AudioDecoder  { byte[] decode(String f) { return new byte[0]; } }
class VideoEncoder  { void encode(byte[] v, String fmt) { } }
class AudioMixer    { void mix(byte[] a) { } }
class FileWriter    { void write(String path, byte[] data) { } }

// Facade — one simple method hides all orchestration
public class VideoConverterFacade {
    private VideoDecoder vd = new VideoDecoder();
    private AudioDecoder ad = new AudioDecoder();
    private VideoEncoder ve = new VideoEncoder();
    private AudioMixer   am = new AudioMixer();
    private FileWriter   fw = new FileWriter();

    public void convert(String input, String format, String output) {
        byte[] video = vd.decode(input);
        byte[] audio = ad.decode(input);
        am.mix(audio);
        ve.encode(video, format);
        fw.write(output, video);
    }
}

// Client just calls:
