// Strategy: ONE class, swappable algorithm
public class Sorter {
    private Comparator<Integer> strategy;
    public void setStrategy(Comparator<Integer> c) { this.strategy = c; }
    public List<Integer> sort(List<Integer> list) {
        list.sort(strategy); return list;
    }
}

Sorter s = new Sorter();
s.setStrategy(Comparator.naturalOrder());
s.sort(List.of(3,1,2)); // [1,2,3]

s.setStrategy(Comparator.reverseOrder()); // changed at RUNTIME
s.sort(List.of(3,1,2)); // [3,2,1]

public interface StockObserver {
    void onPriceChange(String ticker, double newPrice);
}

public class StockMarket {
    private final List<StockObserver> observers = new ArrayList<>();
    private final Map<String, Double> prices    = new HashMap<>();

    public void subscribe(StockObserver o)   { observers.add(o); }
    public void unsubscribe(StockObserver o) { observers.remove(o); }

    public void updatePrice(String ticker, double price) {
        prices.put(ticker, price);
        observers.forEach(o -> o.onPriceChange(ticker, price));
    }
}

public class AlertService implements StockObserver {
    public void onPriceChange(String ticker, double price) {
        if (price > 1000)
            System.out.println("ALERT: " + ticker + " at " + price);
    }
}

