// Thread-safe Observer: CopyOnWriteArrayList + exception isolation
public class SafeEventBus {
    // Safe for concurrent add/remove during iteration
    private final List<StockObserver> observers = new CopyOnWriteArrayList<>();

    public void subscribe(StockObserver o)   { observers.add(o); }
    public void unsubscribe(StockObserver o) { observers.remove(o); }

    public void notifyObservers(String ticker, double price) {
        for (StockObserver o : observers) {
            try {
                o.onPriceChange(ticker, price);
            } catch (Exception e) {
                // Log and continue — one bad observer won't block others
                log.error("Observer failed: " + o.getClass().getSimpleName(), e);
            }
        }
    }
}

