public interface DiscountStrategy {
    double apply(double originalPrice);
}

public class LoyaltyDiscount implements DiscountStrategy {
    public double apply(double price) { return price * 0.85; } // 15% off
}
public class SeasonalDiscount implements DiscountStrategy {
    public double apply(double price) { return price * 0.70; } // 30% off
}
public class NoDiscount implements DiscountStrategy {
    public double apply(double price) { return price; }
}

public class PricingEngine {
    private DiscountStrategy strategy;
    public PricingEngine(DiscountStrategy s) { this.strategy = s; }
    public void setStrategy(DiscountStrategy s) { this.strategy = s; }
    public double calculate(double price) { return strategy.apply(price); }
}

PricingEngine engine = new PricingEngine(new LoyaltyDiscount());
