public interface Command { void execute(); void undo(); }

public class TextEditor {
    private StringBuilder text = new StringBuilder();
    public void insert(int pos, String str) { text.insert(pos, str); }
    public void delete(int pos, int len)    { text.delete(pos, pos+len); }
    public String getText() { return text.toString(); }
}

public class InsertCommand implements Command {
    private final TextEditor editor;
    private final int position;
    private final String text;
    public InsertCommand(TextEditor e, int p, String t) {
        editor = e; position = p; text = t;
    }
    public void execute() { editor.insert(position, text); }
    public void undo()    { editor.delete(position, text.length()); }
}

public class CommandManager {
    private final Deque<Command> undoStack = new ArrayDeque<>();
    private final Deque<Command> redoStack = new ArrayDeque<>();

    public void execute(Command cmd) {
        cmd.execute(); undoStack.push(cmd); redoStack.clear();
    }
    public void undo() {
        if (!undoStack.isEmpty()) { Command c = undoStack.pop(); c.undo(); redoStack.push(c); }
    }
    public void redo() {
        if (!redoStack.isEmpty()) { Command c = redoStack.pop(); c.execute(); undoStack.push(c); }
    }
}

public class MacroCommand implements Command {
    private final List<Command> commands;
    public MacroCommand(List<Command> commands) {
        this.commands = new ArrayList<>(commands);
    }

    @Override
    public void execute() {
        int done = 0;
        try {
            for (Command cmd : commands) {
                cmd.execute(); done++;
            }
        } catch (Exception e) {
            // Rollback: undo already-executed commands in reverse
            for (int i = done - 1; i >= 0; i--)
                commands.get(i).undo();
            throw new RuntimeException("Macro failed, rolled back", e);
        }
    }

    @Override
    public void undo() {
        // Undo all in reverse order
        for (int i = commands.size() - 1; i >= 0; i--)
            commands.get(i).undo();
    }
}

