@Configuration
@EnableStateMachine
public class OrderStateMachineConfig
        extends StateMachineConfigurerAdapter<OrderStatus, OrderEvent> {

    @Override
    public void configure(
            StateMachineStateConfigurer<OrderStatus, OrderEvent> states)
            throws Exception {
        states.withStates()
            .initial(OrderStatus.PENDING)
            .states(EnumSet.allOf(OrderStatus.class));
    }

    @Override
    public void configure(
            StateMachineTransitionConfigurer<OrderStatus, OrderEvent> transitions)
            throws Exception {
        transitions
            .withExternal().source(PENDING).target(PAID)
                .event(OrderEvent.PAYMENT_RECEIVED)
            .and()
            .withExternal().source(PAID).target(SHIPPED)
                .event(OrderEvent.SHIPPED)
            .and()
            .withExternal().source(SHIPPED).target(DELIVERED)
                .event(OrderEvent.DELIVERED);
    }
}

