// Binary tree in-order iterator
public class InOrderIterator implements Iterator<Integer> {
    private final Deque<TreeNode> stack = new ArrayDeque<>();
    public InOrderIterator(TreeNode root) { pushLeft(root); }
    private void pushLeft(TreeNode n) { while (n != null) { stack.push(n); n = n.left; } }
    @Override public boolean hasNext() { return !stack.isEmpty(); }
    @Override public Integer next() {
        TreeNode node = stack.pop();
        pushLeft(node.right);
        return node.val;
    }
}

