// BROKEN DCL — without volatile
public class BrokenSingleton {
    private static BrokenSingleton instance; // NOT volatile — broken!
    private final String config;

    private BrokenSingleton() { this.config = "loaded"; }

    public static BrokenSingleton getInstance() {
        if (instance == null) {
            synchronized (BrokenSingleton.class) {
                if (instance == null) {
                    instance = new BrokenSingleton(); // Thread B may see non-null BEFORE constructor
                }
            }
        }
        return instance;
    }
}

// CORRECT DCL — with volatile
public class CorrectSingleton {
    private static volatile CorrectSingleton instance; // volatile is REQUIRED
    private final String config;

    private CorrectSingleton() { this.config = "loaded"; }

    public static CorrectSingleton getInstance() {
        if (instance == null) {             // 1st check: no sync overhead after init
            synchronized (CorrectSingleton.class) {
                if (instance == null) {     // 2nd check: re-check under lock
                    instance = new CorrectSingleton();
                }
            }
        }
        return instance;
    }
}

// Correct alternative — Bill Pugh Holder (no volatile needed)
public class HolderSingleton {
    private HolderSingleton() {}
    private static class Holder {
        // JVM class init is guaranteed thread-safe (JLS 12.4.2)
        static final HolderSingleton INSTANCE = new HolderSingleton();
    }
    public static HolderSingleton getInstance() { return Holder.INSTANCE; }
}

