public class CompressingDecorator implements DataStore {
    private final DataStore wrapped;
    public CompressingDecorator(DataStore wrapped) { this.wrapped = wrapped; }
    @Override public void save(String key, String value) { wrapped.save(key, compress(value)); }
    @Override public String load(String key) { return decompress(wrapped.load(key)); }
