// Spring AOP self-invocation problem and fix
@Service
public class ProductService {
    @Autowired private ProductRepository repo;
    @Autowired private ProductService self; // inject self to bypass proxy limitation

    @Transactional
    public void createProduct(Product p) {
        repo.save(p);
        // WRONG: self-invocation — applyDiscount bypasses the proxy, runs WITHOUT a new TX!
        // applyDiscount(p.getId());

        // CORRECT: call through the proxy
        self.applyDiscount(p.getId());
    }

    @Transactional(propagation = Propagation.REQUIRES_NEW)
    public void applyDiscount(Long id) {
        repo.update(id, calculateDiscount(id)); // runs in NEW separate transaction
    }
}

