import java.util.concurrent.Flow;
import java.util.concurrent.SubmissionPublisher;

// Java 9 Flow API — reactive observer with back-pressure
public class FlowDemo {

    static class UpperCaseProcessor
            extends SubmissionPublisher<String>
            implements Flow.Processor<String, String> {
        private Flow.Subscription subscription;

        @Override public void onSubscribe(Flow.Subscription s) {
            this.subscription = s;
            s.request(1);
        }
        @Override public void onNext(String item) {
            submit(item.toUpperCase());
            subscription.request(1);
        }
        @Override public void onError(Throwable t) { t.printStackTrace(); }
        @Override public void onComplete() { close(); }
    }

    static class PrintSubscriber implements Flow.Subscriber<String> {
        private Flow.Subscription subscription;
        private final String name;
        PrintSubscriber(String name) { this.name = name; }

        @Override public void onSubscribe(Flow.Subscription s) {
            this.subscription = s;
            s.request(Long.MAX_VALUE);
        }
        @Override public void onNext(String item) {
            System.out.println(name + " received: " + item);
        }
        @Override public void onError(Throwable t) { t.printStackTrace(); }
        @Override public void onComplete() { System.out.println(name + " done"); }
    }

    public static void main(String[] args) throws Exception {
        SubmissionPublisher<String> publisher = new SubmissionPublisher<>();
        UpperCaseProcessor processor = new UpperCaseProcessor();
        publisher.subscribe(processor);
        processor.subscribe(new PrintSubscriber("Sub-1"));
        processor.subscribe(new PrintSubscriber("Sub-2"));
        publisher.submit("hello");
        publisher.submit("world");
        publisher.close();
        Thread.sleep(100);
    }
}

import java.util.*;
import java.util.concurrent.*;

public interface Command { void execute(); void undo(); String describe(); }

// MACRO COMMAND — Composite of commands
public class MacroCommand implements Command {
    private final List<Command> commands = new ArrayList<>();
    private final String name;

    public MacroCommand(String name) { this.name = name; }
    public MacroCommand add(Command cmd) { commands.add(cmd); return this; }

    @Override public void execute() { commands.forEach(Command::execute); }

    @Override
    public void undo() {
        ListIterator<Command> it = commands.listIterator(commands.size());
        while (it.hasPrevious()) it.previous().undo(); // reverse order
    }
    @Override public String describe() { return "Macro: " + name; }
}

// COMMAND QUEUE — asynchronous, ordered execution
public class CommandQueue {
    private final BlockingQueue<Command> queue = new LinkedBlockingQueue<>();
    private final Deque<Command> history = new ArrayDeque<>();
    private final ExecutorService executor = Executors.newSingleThreadExecutor();

    public CommandQueue() {
        executor.submit(() -> {
            while (!Thread.currentThread().isInterrupted()) {
                try {
                    Command cmd = queue.take();
                    cmd.execute();
                    history.push(cmd);
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                }
            }
        });
    }

    public void enqueue(Command cmd) { queue.offer(cmd); }

    public void undoLast() {
        if (!history.isEmpty()) {
            Command cmd = history.pop();
            cmd.undo();
        }
    }
}

// Usage
CommandQueue q = new CommandQueue();
MacroCommand deploy = new MacroCommand("Deploy v2.0")
    .add(new BackupDatabaseCommand())
    .add(new DeployArtifactCommand("app-v2.0.jar"))
    .add(new RunHealthCheckCommand());
q.enqueue(deploy);

// TEMPLATE METHOD approach
public abstract class ReportGenerator {
    public final String generate(DataSet data) { // template method — skeleton
        String raw = extractData(data);            // abstract hook
        String processed = processData(raw);       // hook with default
        String formatted = formatOutput(processed); // abstract hook
        return addHeader() + formatted + addFooter();
    }
    protected abstract String extractData(DataSet data);
    protected abstract String formatOutput(String data);
    protected String processData(String raw) { return raw; } // optional hook
    private String addHeader() { return "=== REPORT START ===\n"; }
    private String addFooter() { return "\n=== REPORT END ==="; }
}

public class CsvReportGenerator extends ReportGenerator {
    @Override protected String extractData(DataSet d) { return d.toCsv(); }
    @Override protected String formatOutput(String d) { return "CSV:\n" + d; }
}
// Cannot switch format at runtime — must instantiate different subclass

// STRATEGY approach
public interface DataExtractor { String extract(DataSet data); }
public interface OutputFormatter { String format(String data); }

public class ReportGeneratorStrategy {
    private DataExtractor extractor;
    private OutputFormatter formatter;

    public ReportGeneratorStrategy(DataExtractor extractor, OutputFormatter formatter) {
        this.extractor = extractor; this.formatter = formatter;
    }

    public void setFormatter(OutputFormatter f) { this.formatter = f; } // runtime switch!

    public String generate(DataSet data) {
        return "=== REPORT START ===\n" + formatter.format(extractor.extract(data))
            + "\n=== REPORT END ===";
    }
}

