// Flyweight — intrinsic state (shared, immutable)
public final class TreeType {
    private final String name;
    private final String color;
    private final String texture;

    public TreeType(String name, String color, String texture) {
        this.name = name; this.color = color; this.texture = texture;
        System.out.println("Creating TreeType: " + name + " (expensive!)");
    }

    // Extrinsic state (x, y) is passed in — NOT stored
    public void draw(int x, int y) {
        System.out.println("Drawing " + name + " at (" + x + "," + y + ")");
    }
}

// FlyweightFactory — manages the shared pool
public class TreeTypeFactory {
    private static final Map<String, TreeType> cache = new HashMap<>();

    public static TreeType getTreeType(String name, String color, String texture) {
        return cache.computeIfAbsent(name + "|" + color,
            k -> new TreeType(name, color, texture)); // create only if absent
    }
}

// Context — holds extrinsic state per tree instance
public class Tree {
    private final int x, y;        // extrinsic — unique per tree
    private final TreeType type;   // intrinsic — shared Flyweight
    public Tree(int x, int y, TreeType type) { this.x = x; this.y = y; this.type = type; }
    public void draw() { type.draw(x, y); }
}

