for (int i = 0; i < 1_000_000; i++) {
    String species = i % 3 == 0 ? "Oak" : i % 3 == 1 ? "Pine" : "Birch";
    TreeType type = TreeTypeFactory.getTreeType(species, "green", species + "_texture.png");
    new Tree(i * 10, i * 5, type).draw();
}

