// Event Sourcing with Command Pattern

// Immutable events
public sealed interface AccountEvent permits MoneyDeposited, MoneyWithdrawn, AccountOpened {
    String accountId();
    java.time.Instant occurredAt();
}
public record AccountOpened(String accountId, java.time.Instant occurredAt, String owner) implements AccountEvent {}
public record MoneyDeposited(String accountId, java.time.Instant occurredAt, java.math.BigDecimal amount) implements AccountEvent {}
public record MoneyWithdrawn(String accountId, java.time.Instant occurredAt, java.math.BigDecimal amount) implements AccountEvent {}

// Aggregate — rebuilds state from events
public class BankAccount {
    private String id;
    private java.math.BigDecimal balance = java.math.BigDecimal.ZERO;
    private final java.util.List<AccountEvent> uncommittedEvents = new java.util.ArrayList<>();

    public static BankAccount reconstitute(java.util.List<AccountEvent> history) {
        BankAccount account = new BankAccount();
        history.forEach(account::apply);
        return account;
    }

    public void deposit(java.math.BigDecimal amount) {
        if (amount.compareTo(java.math.BigDecimal.ZERO) <= 0)
            throw new IllegalArgumentException("Amount must be positive");
        MoneyDeposited event = new MoneyDeposited(id, java.time.Instant.now(), amount);
        apply(event);
        uncommittedEvents.add(event);
    }

    private void apply(AccountEvent event) {
        switch (event) {
            case AccountOpened e -> { this.id = e.accountId(); }
            case MoneyDeposited e -> balance = balance.add(e.amount());
            case MoneyWithdrawn e -> balance = balance.subtract(e.amount());
        }
    }

    public java.math.BigDecimal getBalance() { return balance; }
}

// Event Store — append-only log
public class InMemoryEventStore {
    private final java.util.Map<String, java.util.List<AccountEvent>> store = new java.util.HashMap<>();
    public void append(String id, java.util.List<AccountEvent> events) {
        store.computeIfAbsent(id, k -> new java.util.ArrayList<>()).addAll(events);
    }
    public java.util.List<AccountEvent> load(String id) {
        return store.getOrDefault(id, java.util.List.of());
    }
}

// Element interface
public interface Expression {
    <T> T accept(ExpressionVisitor<T> visitor);
}

// Visitor interface — one visit method per element type
public interface ExpressionVisitor<T> {
    T visitNumber(NumberExpr expr);
    T visitAdd(AddExpr expr);
    T visitMultiply(MultiplyExpr expr);
}

// Concrete Elements
public class NumberExpr implements Expression {
    public final double value;
    public NumberExpr(double value) { this.value = value; }
    @Override public <T> T accept(ExpressionVisitor<T> v) { return v.visitNumber(this); }
}

public class AddExpr implements Expression {
    public final Expression left, right;
    public AddExpr(Expression l, Expression r) { left = l; right = r; }
    @Override public <T> T accept(ExpressionVisitor<T> v) { return v.visitAdd(this); }
}

public class MultiplyExpr implements Expression {
    public final Expression left, right;
    public MultiplyExpr(Expression l, Expression r) { left = l; right = r; }
    @Override public <T> T accept(ExpressionVisitor<T> v) { return v.visitMultiply(this); }
}

// VISITOR 1: Evaluate
public class EvalVisitor implements ExpressionVisitor<Double> {
    @Override public Double visitNumber(NumberExpr e) { return e.value; }
    @Override public Double visitAdd(AddExpr e) { return e.left.accept(this) + e.right.accept(this); }
    @Override public Double visitMultiply(MultiplyExpr e) { return e.left.accept(this) * e.right.accept(this); }
}

// VISITOR 2: Pretty-print — NEW OPERATION, zero changes to elements!
public class PrintVisitor implements ExpressionVisitor<String> {
    @Override public String visitNumber(NumberExpr e) { return String.valueOf(e.value); }
    @Override public String visitAdd(AddExpr e) { return "(" + e.left.accept(this) + " + " + e.right.accept(this) + ")"; }
    @Override public String visitMultiply(MultiplyExpr e) { return "(" + e.left.accept(this) + " * " + e.right.accept(this) + ")"; }
}

// Build: (3 + 4) * 2
Expression expr = new MultiplyExpr(new AddExpr(new NumberExpr(3), new NumberExpr(4)), new NumberExpr(2));
System.out.println(expr.accept(new PrintVisitor())); // ((3.0 + 4.0) * 2.0)
System.out.println(expr.accept(new EvalVisitor()));  // 14.0

