public interface UserRepository {
    Optional<User> findById(Long id);
    Optional<User> findByEmail(String email);
    List<User> findAllActive();
    User save(User user);
    void delete(Long id);
}

// JPA implementation
@Repository
public class JpaUserRepository implements UserRepository {
    @PersistenceContext private EntityManager em;
    @Override public Optional<User> findById(Long id) { return Optional.ofNullable(em.find(User.class, id)); }
    @Override public List<User> findAllActive() {
        return em.createQuery("SELECT u FROM User u WHERE u.active = true", User.class).getResultList();
    }
    @Override public User save(User user) {
        if (user.getId() == null) em.persist(user); else em.merge(user); return user;
    }
    @Override public Optional<User> findByEmail(String email) { return Optional.empty(); }
    @Override public void delete(Long id) { em.remove(em.find(User.class, id)); }
}

// In-memory implementation — for unit testing
public class InMemoryUserRepository implements UserRepository {
    private final Map<Long, User> store = new HashMap<>();
    private long nextId = 1L;
    @Override public Optional<User> findById(Long id) { return Optional.ofNullable(store.get(id)); }
    @Override public User save(User user) {
        if (user.getId() == null) user.setId(nextId++); store.put(user.getId(), user); return user;
    }
    @Override public Optional<User> findByEmail(String email) { return store.values().stream().filter(u -> u.getEmail().equals(email)).findFirst(); }
    @Override public List<User> findAllActive() { return store.values().stream().filter(User::isActive).toList(); }
    @Override public void delete(Long id) { store.remove(id); }
}

