// Demonstrating all SOLID principles through Decorator

public interface MessageSender { void send(String to, String message); }

@Service
public class SmtpMessageSender implements MessageSender {
    @Override public void send(String to, String message) {
        System.out.println("SMTP: sending to " + to + ": " + message);
    }
}

public abstract class MessageSenderDecorator implements MessageSender {
    protected final MessageSender wrapped;
    public MessageSenderDecorator(MessageSender wrapped) { this.wrapped = wrapped; }
}

// SRP: handles ONLY logging
public class LoggingDecorator extends MessageSenderDecorator {
    public LoggingDecorator(MessageSender wrapped) { super(wrapped); }
    @Override public void send(String to, String message) {
        System.out.println("Sending to: " + to);
        wrapped.send(to, message);
        System.out.println("Sent successfully");
    }
}

// SRP: handles ONLY retry logic
public class RetryDecorator extends MessageSenderDecorator {
    private final int maxRetries;
    public RetryDecorator(MessageSender wrapped, int maxRetries) {
        super(wrapped); this.maxRetries = maxRetries;
    }
    @Override public void send(String to, String message) {
        for (int attempt = 1; attempt <= maxRetries; attempt++) {
            try { wrapped.send(to, message); return; }
            catch (Exception e) { if (attempt == maxRetries) throw e; }
        }
    }
}

