// Originator
public class TextEditor {
    private String content;
    private int cursorPosition;

    public TextEditor() { this.content = ""; this.cursorPosition = 0; }

    public void type(String text) {
        content = content.substring(0, cursorPosition) + text + content.substring(cursorPosition);
        cursorPosition += text.length();
    }

    // Create a snapshot
    public Snapshot save() { return new Snapshot(content, cursorPosition); }

    // Restore from snapshot
    public void restore(Snapshot snapshot) {
        this.content = snapshot.content;
        this.cursorPosition = snapshot.cursorPosition;
    }

    public String getContent() { return content; }

    // Memento — nested; only TextEditor can access its fields
    public static class Snapshot {
        private final String content;
        private final int cursorPosition;
        private Snapshot(String content, int cursorPosition) {
            this.content = content; this.cursorPosition = cursorPosition;
        }
        // No public getters — Caretaker cannot inspect state
    }
}

// Caretaker — manages history without knowing state
public class EditorHistory {
    private final java.util.Deque<TextEditor.Snapshot> history = new java.util.ArrayDeque<>();
    public void push(TextEditor.Snapshot s) { history.push(s); }
    public TextEditor.Snapshot pop() { return history.isEmpty() ? null : history.pop(); }
}

// Usage
TextEditor editor = new TextEditor();
EditorHistory history = new EditorHistory();
history.push(editor.save()); // snapshot 1: ""
editor.type("Hello");
history.push(editor.save()); // snapshot 2: "Hello"
editor.type(" World");
System.out.println(editor.getContent()); // "Hello World"
editor.restore(history.pop());
System.out.println(editor.getContent()); // "Hello"
editor.restore(history.pop());
System.out.println(editor.getContent()); // ""

