Comparator<String> byLengthThenAlpha = byLength.thenComparing(Comparator.naturalOrder());
words.sort(byLengthThenAlpha);

// Custom functional strategy interface
@FunctionalInterface
public interface DiscountStrategy {
    double apply(double price);
    default DiscountStrategy andThen(DiscountStrategy next) {
        return price -> next.apply(this.apply(price)); // compose strategies
    }
}

public class ShoppingCart {
    private DiscountStrategy discount;
    public ShoppingCart(DiscountStrategy discount) { this.discount = discount; }
    public double total(double subtotal) { return discount.apply(subtotal); }
}

// Strategies as lambdas
DiscountStrategy tenPercent = price -> price * 0.90;
DiscountStrategy fiveFlat = price -> price - 5.0;
DiscountStrategy vipDiscount = tenPercent.andThen(fiveFlat); // compose

System.out.println(new ShoppingCart(vipDiscount).total(100.0)); // 85.0

// Predicate composition
Predicate<String> isLong = s -> s.length() > 5;
Predicate<String> startsWithA = s -> s.startsWith("A");
List.of("Alice", "Alexander", "Bob", "Al")
    .stream().filter(isLong.and(startsWithA)).forEach(System.out::println); // Alexander

// Function pipeline
Function<String, String> pipeline =
    ((Function<String,String>) String::trim).andThen(String::toUpperCase).andThen(s -> "MR_" + s);
System.out.println(pipeline.apply("  alice  ")); // MR_ALICE

// Strategy vs State — the most confused pair
public class Sorter {
    private final Comparator<Integer> strategy; // chosen by client, stays
    public Sorter(Comparator<Integer> s) { this.strategy = s; }
    public void sort(List<Integer> list) { list.sort(strategy); }
}
// State: transitions automatically
public class TrafficLight {
    private String state = "RED";
    public void tick() {
        state = switch (state) {
            case "RED" -> "GREEN";
            case "GREEN" -> "YELLOW";
            default -> "RED";
        }; // no client picks the state
    }
}

