// STRUCTURAL problems and solutions

// Problem: interface mismatch → ADAPTER
LegacyLogger oldLogger = new Log4jLegacyLogger();
ModernLogger adapter = new LegacyLoggerAdapter(oldLogger);

// Problem: add features without modifying class → DECORATOR
Cache cache = new RedisCache();
cache = new MetricsDecorator(cache);
cache = new LoggingDecorator(cache);

// Problem: complex subsystem, simple access needed → FACADE
VideoConverter facade = new VideoConverterFacade();
facade.convert("input.avi", "output.mp4"); // hides codec, muxer, resampler

// Problem: control access, lazy load → PROXY
HeavyReport report = new LazyReportProxy(); // created lazily
report.generate(); // RealReport created only NOW, on first access

// BEHAVIORAL problems and solutions

// Problem: algorithm varies at runtime → STRATEGY
public class Processor {
    private SortStrategy strategy;
    public void setStrategy(SortStrategy s) { this.strategy = s; }
    public void process(int[] data) { strategy.sort(data); }
}
new Processor().setStrategy(new QuickSort());

// Problem: react to state changes → OBSERVER
orderService.onOrderPlaced(inventoryService::reserve);
orderService.onOrderPlaced(notificationService::sendEmail);

// Problem: object's behavior depends on state → STATE
Order order = new Order(); // starts in PendingState
order.pay();  // transitions to PaidState automatically
order.ship(); // transitions to ShippedState

// Problem: multiple handlers for a request → CHAIN
RequestHandler chain = new AuthHandler();
chain.setNext(new RateLimitHandler()).setNext(new BusinessHandler());
chain.handle(request);

